-// ─── Furniture drawing ─────────────────────────────────────────────
-
-function drawThrone(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
-  // Ornate gold throne with red cushion, 28x32 px approx
-  ctx.save();
-  ctx.translate(x, y);
-  ctx.scale(s, s);
-  // Backrest frame (gold)
-  ctx.fillStyle = '#d4af37';
-  ctx.fillRect(4, 0, 20, 28);
-  // Cushion (red)
-  ctx.fillStyle = '#a32a2a';
-  ctx.fillRect(6, 18, 16, 10);
-  // Decorative top arch
-  ctx.beginPath();
-  ctx.moveTo(4, 0);
-  ctx.bezierCurveTo(14, -12, 24, 0, 24, 0);
-  ctx.lineTo(4, 0);
-  ctx.fill();
-  // Legs
-  ctx.fillRect(4, 28, 6, 4);
-  ctx.fillRect(18, 28, 6, 4);
-  ctx.restore();
-}
-
-function drawPlanningTable(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
-  // Wood table with map scroll, 30x24 px approx
-  ctx.save();
-  ctx.translate(x, y);
-  ctx.scale(s, s);
-  // Table top (brown wood)
-  ctx.fillStyle = '#6b4c2b';
-  ctx.fillRect(0, 8, 30, 12);
-  // Table legs
-  ctx.fillRect(2, 20, 4, 6);
-  ctx.fillRect(24, 20, 4, 6);
-  // Map scroll (light parchment)
-  ctx.fillStyle = '#d9cba3';
-  ctx.fillRect(6, 10, 18, 8);
-  // Map details (green lines)
-  ctx.strokeStyle = '#3a6b35';
-  ctx.lineWidth = 1;
-  ctx.beginPath();
-  ctx.moveTo(8, 12);
-  ctx.lineTo(22, 14);
-  ctx.moveTo(10, 16);
-  ctx.lineTo(20, 18);
-  ctx.stroke();
-  ctx.restore();
-}
-
-function drawWeaponRack(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
-  // Weapon rack with sword silhouettes, 28x28 px approx
-  ctx.save();
-  ctx.translate(x, y);
-  ctx.scale(s, s);
-  // Rack frame (dark wood)
-  ctx.fillStyle = '#4a2f1a';
-  ctx.fillRect(2, 4, 24, 20);
-  // Crossbars
-  ctx.fillRect(2, 8, 24, 3);
-  ctx.fillRect(2, 16, 24, 3);
-  // Swords (gray blades)
-  ctx.strokeStyle = '#a0a0a0';
-  ctx.lineWidth = 2;
-  // Sword 1
-  ctx.beginPath();
-  ctx.moveTo(8, 7);
-  ctx.lineTo(8, 21);
-  ctx.moveTo(6, 7);
-  ctx.lineTo(10, 7);
-  // Sword 2
-  ctx.moveTo(16, 7);
-  ctx.lineTo(16, 21);
-  ctx.moveTo(14, 7);
-  ctx.lineTo(18, 7);
-  ctx.stroke();
-  ctx.restore();
-}
-
-function drawWorkbench(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
-  // Workbench with tools, 32x24 px approx
-  ctx.save();
-  ctx.translate(x, y);
-  ctx.scale(s, s);
-  // Bench top (medium brown)
-  ctx.fillStyle = '#7a5230';
-  ctx.fillRect(0, 8, 32, 12);
-  // Legs
-  ctx.fillRect(2, 20, 6, 4);
-  ctx.fillRect(24, 20, 6, 4);
-  // Hammer (handle + head)
-  ctx.strokeStyle = '#3a2f2a';
-  ctx.lineWidth = 2;
-  ctx.beginPath();
-  ctx.moveTo(8, 14);
-  ctx.lineTo(8, 18);
-  ctx.moveTo(6, 18);
-  ctx.lineTo(10, 18);
-  ctx.stroke();
-  // Saw blade (gray jagged)
-  ctx.fillStyle = '#a0a0a0';
-  ctx.beginPath();
-  ctx.moveTo(20, 14);
-  for (let i = 0; i < 5; i++) {
-    ctx.lineTo(20 + i * 2, 14 + (i % 2 === 0 ? 4 : 0));
-  }
-  ctx.lineTo(30, 18);
-  ctx.closePath();
-  ctx.fill();
-  ctx.restore();
-}
-
-function drawPotionShelf(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
-  // Shelf with colored bottles, 28x28 px approx
-  ctx.save();
-  ctx.translate(x, y);
-  ctx.scale(s, s);
-  // Shelf frame (dark wood)
-  ctx.fillStyle = '#4a2f1a';
-  ctx.fillRect(2, 4, 24, 20);
-  // Shelf boards
-  ctx.fillRect(2, 8, 24, 3);
-  ctx.fillRect(2, 16, 24, 3);
-  // Bottles (red, blue, green)
-  const bottleColors = ['#c33', '#339', '#393'];
-  for (let i = 0; i < 3; i++) {
-    ctx.fillStyle = bottleColors[i];
-    ctx.beginPath();
-    ctx.ellipse(8 + i * 8, 12, 4, 6, 0, 0, Math.PI * 2);
-    ctx.fill();
-    ctx.strokeStyle = '#222';
-    ctx.lineWidth = 1;
-    ctx.stroke();
-  }
-  ctx.restore();
-}
-
-function drawScribeDesk(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
-  // Desk with quill and book, 30x24 px approx
-  ctx.save();
-  ctx.translate(x, y);
-  ctx.scale(s, s);
-  // Desk top (light wood)
-  ctx.fillStyle = '#a67c4f';
-  ctx.fillRect(0, 8, 30, 12);
-  // Legs
-  ctx.fillRect(2, 20, 6, 4);
-  ctx.fillRect(22, 20, 6, 4);
-  // Book (dark cover)
-  ctx.fillStyle = '#3a2f2a';
-  ctx.fillRect(6, 12, 10, 6);
-  // Quill (white feather + black tip)
-  ctx.strokeStyle = '#000';
-  ctx.lineWidth = 1.5;
-  ctx.beginPath();
-  ctx.moveTo(20, 12);
-  ctx.lineTo(24, 18);
-  ctx.moveTo(23, 17);
-  ctx.lineTo(25, 15);
-  ctx.stroke();
-  ctx.fillStyle = '#eee';
-  ctx.beginPath();
-  ctx.ellipse(22, 14, 2, 5, Math.PI / 4, 0, Math.PI * 2);
-  ctx.fill();
-  ctx.restore();
-}
-
-function drawHealingBasin(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
-  // Basin with glowing water, 28x24 px approx
-  ctx.save();
-  ctx.translate(x, y);
-  ctx.scale(s, s);
-  // Basin base (stone gray)
-  ctx.fillStyle = '#7a7a7a';
-  ctx.beginPath();
-  ctx.ellipse(14, 18, 14, 8, 0, 0, Math.PI * 2);
-  ctx.fill();
-  // Water (blue with glow)
-  const gradient = ctx.createRadialGradient(14, 18, 2, 14, 18, 14);
-  gradient.addColorStop(0, 'rgba(100,180,255,0.8)');
-  gradient.addColorStop(1, 'rgba(0,0,80,0)');
-  ctx.fillStyle = gradient;
-  ctx.beginPath();
-  ctx.ellipse(14, 18, 12, 6, 0, 0, Math.PI * 2);
-  ctx.fill();
-  // Glow particles
-  for (let i = 0; i < 6; i++) {
-    const px = 14 + (Math.random() - 0.5) * 20;
-    const py = 18 + (Math.random() - 0.5) * 12;
-    ctx.fillStyle = 'rgba(100,180,255,0.3)';
-    ctx.beginPath();
-    ctx.arc(px, py, 2, 0, Math.PI * 2);
-    ctx.fill();
-  }
-  ctx.restore();
-}
+// ─── Furniture drawing ─────────────────────────────────────────────
+
+function drawThrone(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Detailed ornate gold throne with red cushion, 28x32 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+
+  // Backrest frame with ornate carvings
+  ctx.fillStyle = '#d4af37';
+  ctx.beginPath();
+  ctx.moveTo(4, 28);
+  ctx.lineTo(4, 4);
+  ctx.bezierCurveTo(4, 0, 24, 0, 24, 4);
+  ctx.lineTo(24, 28);
+  ctx.closePath();
+  ctx.fill();
+
+  // Decorative top arch with jewel
+  ctx.fillStyle = '#b8860b';
+  ctx.beginPath();
+  ctx.moveTo(4, 4);
+  ctx.bezierCurveTo(14, -12, 24, 4, 24, 4);
+  ctx.closePath();
+  ctx.fill();
+  ctx.fillStyle = '#ff0000';
+  ctx.beginPath();
+  ctx.ellipse(14, 0, 3, 4, 0, 0, Math.PI * 2);
+  ctx.fill();
+
+  // Red cushion with shading
+  ctx.fillStyle = '#a32a2a';
+  ctx.fillRect(6, 18, 16, 10);
+  ctx.fillStyle = '#7f1f1f';
+  ctx.fillRect(6, 22, 16, 2);
+
+  // Armrests with gold details
+  ctx.fillStyle = '#d4af37';
+  ctx.fillRect(0, 18, 4, 10);
+  ctx.fillRect(24, 18, 4, 10);
+  ctx.strokeStyle = '#b8860b';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(2, 18);
+  ctx.lineTo(2, 28);
+  ctx.moveTo(26, 18);
+  ctx.lineTo(26, 28);
+  ctx.stroke();
+
+  // Legs with carved details
+  ctx.fillStyle = '#b8860b';
+  ctx.fillRect(4, 28, 6, 4);
+  ctx.fillRect(18, 28, 6, 4);
+  ctx.strokeStyle = '#8b6914';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(4, 28);
+  ctx.lineTo(10, 32);
+  ctx.moveTo(24, 28);
+  ctx.lineTo(18, 32);
+  ctx.stroke();
+
+  ctx.restore();
+}
+
+function drawPlanningTable(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Detailed wood table with map scroll and tools, 30x24 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+
+  // Table top with wood grain
+  ctx.fillStyle = '#6b4c2b';
+  ctx.fillRect(0, 8, 30, 12);
+  ctx.strokeStyle = '#5a3f23';
+  ctx.lineWidth = 1;
+  for (let i = 2; i < 30; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 8);
+    ctx.lineTo(i, 20);
+    ctx.stroke();
+  }
+
+  // Table legs with shading
+  ctx.fillStyle = '#4e3a1f';
+  ctx.fillRect(2, 20, 4, 6);
+  ctx.fillRect(24, 20, 4, 6);
+  ctx.strokeStyle = '#3b2b14';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(2, 20);
+  ctx.lineTo(6, 26);
+  ctx.moveTo(28, 20);
+  ctx.lineTo(24, 26);
+  ctx.stroke();
+
+  // Map scroll (light parchment) with creases and edges
+  ctx.fillStyle = '#d9cba3';
+  ctx.fillRect(6, 10, 18, 8);
+  ctx.strokeStyle = '#bfae7a';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(6, 10);
+  ctx.lineTo(24, 10);
+  ctx.lineTo(24, 18);
+  ctx.lineTo(6, 18);
+  ctx.closePath();
+  ctx.stroke();
+
+  // Map details (green lines and dots)
+  ctx.strokeStyle = '#3a6b35';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(8, 12);
+  ctx.lineTo(22, 14);
+  ctx.moveTo(10, 16);
+  ctx.lineTo(20, 18);
+  ctx.stroke();
+  ctx.fillStyle = '#2e5528';
+  ctx.beginPath();
+  ctx.arc(12, 14, 1, 0, Math.PI * 2);
+  ctx.arc(18, 16, 1, 0, Math.PI * 2);
+  ctx.fill();
+
+  // Quill and inkpot on table corner
+  ctx.strokeStyle = '#000';
+  ctx.lineWidth = 1.5;
+  ctx.beginPath();
+  ctx.moveTo(22, 18);
+  ctx.lineTo(26, 22);
+  ctx.moveTo(25, 21);
+  ctx.lineTo(27, 19);
+  ctx.stroke();
+  ctx.fillStyle = '#222';
+  ctx.beginPath();
+  ctx.ellipse(26, 22, 2, 1.5, 0, 0, Math.PI * 2);
+  ctx.fill();
+
+  ctx.restore();
+}
+
+function drawWeaponRack(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Detailed weapon rack with swords and axes, 28x28 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+
+  // Rack frame (dark wood) with texture
+  ctx.fillStyle = '#4a2f1a';
+  ctx.fillRect(2, 4, 24, 20);
+  ctx.strokeStyle = '#3b2613';
+  ctx.lineWidth = 1;
+  for (let i = 4; i < 26; i += 3) {
+    ctx.beginPath();
+    ctx.moveTo(i, 4);
+    ctx.lineTo(i, 24);
+    ctx.stroke();
+  }
+
+  // Crossbars with nails
+  ctx.fillRect(2, 8, 24, 3);
+  ctx.fillRect(2, 16, 24, 3);
+  ctx.fillStyle = '#3b2613';
+  for (let i = 4; i < 26; i += 6) {
+    ctx.beginPath();
+    ctx.arc(i, 9, 1, 0, Math.PI * 2);
+    ctx.arc(i, 17, 1, 0, Math.PI * 2);
+    ctx.fill();
+  }
+
+  // Swords (gray blades) with hilts and pommels
+  ctx.strokeStyle = '#a0a0a0';
+  ctx.lineWidth = 2;
+  // Sword 1
+  ctx.beginPath();
+  ctx.moveTo(8, 7);
+  ctx.lineTo(8, 21);
+  ctx.moveTo(6, 7);
+  ctx.lineTo(10, 7);
+  ctx.moveTo(7, 21);
+  ctx.lineTo(9, 21);
+  ctx.stroke();
+
+  // Sword 2
+  ctx.beginPath();
+  ctx.moveTo(16, 7);
+  ctx.lineTo(16, 21);
+  ctx.moveTo(14, 7);
+
